                // Further hooks on C1.c.a.c could reveal how this error is processed.
            }
            // Intercept CLOSE_FORCE event details
            else if (cVar.name() === "CLOSE_FORCE") {
                const client = hashMap.get("client");
                console.log(`  [-] WebSocket Close Forced for client: ${client}`);
            }

            // Call the original method to ensure normal app execution
            this.a(cVar, hashMap);
