        // Optionally, hook the Handlers' post method to see all Runnables dispatched
        const Handler = Java.use("android.os.Handler");
        Handler.post.implementation = function(runnable) {
            console.log(`[Handler::post] Runnable posted: ${runnable.$className}`);
            // If z1.e is a Runnable (or other relevant Runnables like C1.h, C1.g)
